// Build an HTML digest table from the aggregated rows
const rows = $input.all().map(i => i.json);
const tr = rows.map(r =>
  `<tr><td>${r.symbol ?? ''}</td><td>${r.price ?? ''}</td><td>${r.count ?? 1}</td></tr>`
).join('');
const html = `<h2>Asset digest</h2><table border="1" cellpadding="4">
<tr><th>ID</th><th>price</th><th>Count</th></tr>${tr}</table>`;
return [{ json: { html, rowCount: rows.length, generatedAt: new Date().toISOString() } }];

// Build a stable idempotency key per asset (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.symbol, j.price].join('|')) } };
});
